import type { PointsConfig } from '@smartcart/shared-types';
import type { SessionItem } from '../entities/shopping-session.entity';

/**
 * Strategy contract for points calculation (README §2.3 Points / Open-Closed).
 * Adding a scheme = add a class implementing this + register it in the resolver;
 * no existing code changes. Pure domain — no dependencies, just math.
 */
export interface IPointsCalculationStrategy {
  /** Discriminator matched against `pointsConfig.type`. */
  readonly strategyType: PointsConfig['type'];

  /** Points awarded for a single session line. */
  calculate(item: SessionItem, config: PointsConfig): number;
}
